#include <stdio.h>
#include <stdlib.h>

int maxSumAfterPartitioning(int* arr, int arrSize, int k) {
    int* memo = (int*)malloc(arrSize * sizeof(int));
    for (int i = 0; i < arrSize; i++) {
        memo[i] = -1;
    }

    int helper(int start) {
        if (start == arrSize) return 0;
        if (memo[start] != -1) return memo[start];

        int maxSum = 0;
        int maxElem = 0;
        for (int length = 1; length <= k && start + length <= arrSize; length++) {
            maxElem = maxElem > arr[start + length - 1] ? maxElem : arr[start + length - 1];
            int currentSum = maxElem * length + helper(start + length);
            maxSum = maxSum > currentSum ? maxSum : currentSum;
        }
        memo[start] = maxSum;
        return maxSum;
    }

    return helper(0);
}

int main() {
    int arr[] = {1, 15, 7, 9, 2, 5, 10};
    int k = 3;
    printf("Maximum sum after partitioning: %d\n", maxSumAfterPartitioning(arr, 7, k));
    return 0;
}

